import React from 'react';
import { useCurrentFrame, interpolate } from 'remotion';
import { HOUSE_EASE } from '../../../lib/easing';
import { PlacementBox } from '../../../lib/canvas';
import { fadeOutSchema, type FadeOutProps } from './schema';

export { fadeOutSchema, type FadeOutProps };

/**
 * The inverse of {@link FadeIn}: a pure opacity exit. Opacity goes from 1 to 0
 * starting at `delay`, eased on `HOUSE_EASE`. Slightly faster than entrances
 * (`DURATION.fast`) so the moment ends without lingering — restraint applied
 * to exits as well.
 *
 * Motion is opacity-only by design — no transform, no blur, no scale. Per
 * `CLAUDE.md §4`, `HOUSE_EASE` on `interpolate` is the canonical curve for
 * fades.
 *
 * @example
 * <FadeOut text="Onda" delay={30} duration={10} />
 */
export const FadeOut: React.FC<FadeOutProps> = ({
  text, delay, duration, color, fontSize, fontFamily,
  fontWeight = 600, letterSpacing = 'normal', lineHeight = 1.1, align = 'left', placement,
}) => {
  const frame = useCurrentFrame();
  const local = Math.max(0, frame - delay);

  const opacity = interpolate(local, [0, duration], [1, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
    easing: HOUSE_EASE,
  });

  return (
    <PlacementBox placement={placement}>
      <div style={{
        opacity,
        color, fontSize, fontFamily, fontWeight, letterSpacing, lineHeight,
        textAlign: align,
      }}>
        {text}
      </div>
    </PlacementBox>
  );
};

export default FadeOut;

import { z } from 'zod';
import { DURATION } from '../../../lib/motion';
import { placementSchema } from '../../../lib/canvas-schemas';

/** Zod schema for {@link FadeOut} props — drives Remotion `defaultProps` validation. */
export const fadeOutSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted (`schema.parse({})` works as before). Lets consumers build `z.discriminatedUnion('kind', [...])` directly over onda schemas. */
  kind: z.literal('fade-out').default('fade-out'),
  /** What to fade out. */
  text: z.string().default('Onda'),
  /** Frames before the fade begins. */
  delay: z.number().int().min(0).default(0),
  /** Frames to fully reach opacity 0. Default `DURATION.fast` (10) — exits are quicker than entrances. */
  duration: z.number().int().min(1).default(DURATION.fast),
  /** Text color. Defaults to `--onda-text` (`#F2F2F4`). */
  color: z.string().default('var(--onda-text, #F2F2F4)'),
  /** Pixels. */
  fontSize: z.number().default(96),
  /** Onda display font. Never default to Inter / Arial / system. */
  fontFamily: z.string().default('var(--onda-font-display, "Clash Display", sans-serif)'),
  /** Font weight. Display default `600`. */
  fontWeight: z.number().optional(),
  /** CSS letter-spacing (e.g. `'-0.02em'`, `'0.06em'`). Default `'normal'`. */
  letterSpacing: z.string().optional(),
  /** Unitless line height. Default `1.1` for tight display copy. */
  lineHeight: z.number().optional(),
  /** Text alignment. */
  align: z.enum(['left', 'center', 'right']).optional(),
  /** Where on the canvas this sits. Region (`'center'`, `'upper-third'`, ...) or `{ x, y, anchor }` in 0..1 canvas fractions. Coordinates may be negative or >1 for off-canvas. */
  placement: placementSchema.optional(),
});

/** Inferred props for {@link FadeOut}. */
export type FadeOutProps = z.infer<typeof fadeOutSchema>;

# FadeOut

The inverse of `FadeIn`: a pure opacity exit. Opacity goes from 1 to 0 starting at `delay`, eased on `HOUSE_EASE`. No transform, no blur, no scale — just the cleanest possible way to remove an element from the frame. Slightly faster than entrances (`DURATION.fast`) so the moment ends without lingering. Restraint applied to exits as well.

## Props

| Name | Type | Default | Notes |
| --- | --- | --- | --- |
| `text` | `string` | `"Onda"` | What to fade out. |
| `delay` | `integer ≥ 0` | `0` | Frames before the fade begins. |
| `duration` | `integer ≥ 1` | `DURATION.fast` (10) | Frames to reach opacity 0. Exits are quicker than entrances by design. |
| `color` | `string` | `"#F2F2F4"` | Text color — defaults to `--onda-text`. |
| `fontSize` | `number` | `96` | Pixels. |
| `fontFamily` | `string` | `'"Clash Display", sans-serif'` | The Onda display font. Never default to Inter / Arial / system. |
| `fontWeight` | `number` | `600` | Font weight. |
| `letterSpacing` | `string` | `"normal"` | CSS letter-spacing (e.g. `"-0.02em"`, `"0.06em"`). |
| `lineHeight` | `number` | `1.1` | Unitless line height. |
| `align` | `"left" \| "center" \| "right"` | `"left"` | Text alignment. |
| `placement` | `Placement?` | – | Where on the canvas this sits. Region (`"center"`, `"upper-third"`, …) or `{ x, y, anchor }` in 0..1 canvas fractions. Coordinates may be negative or >1 for off-canvas. |

## Usage

```tsx
import { Composition } from 'remotion';
import { FadeOut, fadeOutSchema } from './components/onda/fade-out/FadeOut';

export const Root: React.FC = () => (
  <Composition
    id="MyFadeOut"
    component={FadeOut}
    durationInFrames={60}
    fps={30}
    width={1080}
    height={1920}
    schema={fadeOutSchema}
    defaultProps={{
      text: 'Onda',
      delay: 30,
      duration: 10,
      color: '#F2F2F4',
      fontSize: 96,
      fontFamily: '"Clash Display", sans-serif',
    }}
  />
);
```

## Motion notes

- Pure opacity exit — no transform, no blur, no scale. Per `CLAUDE.md §4`, `HOUSE_EASE` on `interpolate` is the canonical curve for fades; physical motion would use a spring.
- Duration defaults to `DURATION.fast` (10 frames ≈ 0.33s at 30fps), shorter than the `DURATION.base` (18) used by entrances. Exits should clear the frame quickly so the next beat lands.
- Opacity clamps at both ends — frame 0 renders fully opaque, any frame past `delay + duration` renders fully transparent.
- Pair with `FadeIn` (and matching `delay`s via `<Sequence>`) for a complete enter-hold-exit cycle on a single element.
